// Pick the newest TWO SharePoint versions for this file and emit a single item.
// `name` keeps the SharePoint original (spaces allowed). `storage_basename`
// matches shared.object_storage.safe_upload_basename for MinIO keys.
function safeUploadBasename(original) {
  const base = String(original || '').split(/[/\\]/).pop() || '';
  const dot = base.lastIndexOf('.');
  const stem = dot >= 0 ? base.slice(0, dot) : base;
  const ext = dot >= 0 ? base.slice(dot).toLowerCase() : '';
  let stemSafe = stem.normalize('NFC').normalize('NFKD').replace(/[\u0300-\u036f]/g, '');
  stemSafe = stemSafe.replace(/[^\x00-\x7F]/g, '');
  stemSafe = stemSafe.replace(/[^A-Za-z0-9._-]+/g, '_').replace(/_+/g, '_').replace(/^[._-]+|[._-]+$/g, '');
  if (!stemSafe) stemSafe = 'file';
  if (stemSafe.length > 180) {
    stemSafe = stemSafe.slice(0, 180).replace(/[._-]+$/, '') || 'file';
  }
  return stemSafe + ext;
}

const item = $input.first();
if (!item) {
  return [];
}
const j = item.json || {};
const name = j.name;
const fileId = j.id;
const versions = Array.isArray(j.value) ? j.value.slice() : [];
if (!name || !fileId || versions.length === 0) {
  return [];
}

versions.sort((a, b) => parseFloat(b.id) - parseFloat(a.id));
const newest = versions[0];
const previous = versions[1] || null;

const storage_basename = safeUploadBasename(name);
const file_key = 'uploads/' + storage_basename;
const file_path = 's3://ifcpipeline/' + file_key;

const buildEtag = (v) => v ? ('sp:' + fileId + ':v' + v.id) : null;
const shape = (v) => v ? {
  sp_version_id: String(v.id),
  download_url: v['@microsoft.graph.downloadUrl'],
  size: v.size,
  last_modified: v.lastModifiedDateTime,
  etag: buildEtag(v),
} : null;

return [{
  json: {
    name,
    storage_basename,
    file_key,
    file_path,
    sp_file_id: fileId,
    sp_new: shape(newest),
    sp_prev: shape(previous),
    has_prev: !!previous,
  },
}];

